     1|/*
     2| * IVX Reels — enterprise full-screen vertical video experience for ivxholding.com.
     3| *
     4| * Instagram-grade behaviors on top of the IVX video platform API:
     5| *   full-screen snap feed · infinite scroll · autoplay/pause · adaptive HLS
     6| *   double-tap like · comments · share · save · follow · stories · live row
     7| *   audience channels (Investor / Buyer / Realtor / Builder / JV Deals)
     8| *   personalized ranking (viewer id + zip + watch history) · analytics beacons
     9| *   upload with progress (mobile + desktop) · creator dashboard · report
    10| */
    11|(function () {
    12|  'use strict';
    13|  if (window.__ivxReelsLoaded) return;
    14|  window.__ivxReelsLoaded = true;
    15|
    16|  /* ---------- config ---------- */
    17|  /*
    18|   * API resolution — the static landing host (ivxholding.com on S3) answers every
    19|   * /api/* path with index.html, which is NOT an API. We must always talk to the
    20|   * real backend. Preference order:
    21|   *   1. meta[ivx-backend-url]   (real backend, e.g. https://api.ivxholding.com)
    22|   *   2. meta[ivx-api-url]       (only if it is not the static site itself)
    23|   *   3. https://api.ivxholding.com
    24|   * Plus runtime failover: if a feed response is not JSON (static-site HTML) or
    25|   * the request fails, the next candidate host is promoted automatically.
    26|   */
    27|  var PROD_API = 'https://api.ivxholding.com';
    28|  var RENDER_API = 'https://ivx-holdings-platform.onrender.com';
    29|  function readMeta(name) {
    30|    var m = document.querySelector('meta[name="' + name + '"]');
    31|    var v = (m && m.getAttribute('content')) || '';
    32|    v = v.trim().replace(/\/+$/, '');
    33|    if (!v || v.indexOf('__IVX') === 0) return '';
    34|    return v;
    35|  }
    36|  function isStaticSiteHost(url) {
    37|    try {
    38|      var h = new URL(url).host.toLowerCase();
    39|      if (h === 'ivxholding.com' || h === 'www.ivxholding.com') return true;
    40|      if (location.host && h === location.host.toLowerCase()) return true;
    41|      return false;
    42|    } catch (e) { return true; }
    43|  }
    44|  var API = readMeta('ivx-backend-url') || readMeta('ivx-api-url') || PROD_API;
    45|  if (isStaticSiteHost(API)) API = PROD_API;
    46|  var API_CANDIDATES = [API, PROD_API, RENDER_API].filter(function (v, i, a) { return v && a.indexOf(v) === i; });
    47|
    48|  var HLS_CDN = 'https://cdn.jsdelivr.net/npm/hls.js@1.5.20/dist/hls.min.js';
    49|  /*
    50|   * Channels — '' is the CANONICAL unified feed (identical order on landing,
    51|   * Android, iOS, Expo): 3 investor deal videos → 1 Featured Investor Video →
    52|   * repeat. '__reels' is the Project Reels rail (?type=reel) — construction
    53|   * updates never interrupt the investor deal flow.
    54|   */
    55|  var CHANNELS = [
    56|    { id: '', label: 'Deals' },
    57|    { id: '__reels', label: 'Project Reels' },
    58|    { id: 'investor', label: 'Investor' },
    59|    { id: 'buyer', label: 'Buyer' },
    60|    { id: 'realtor', label: 'Realtor' },
    61|    { id: 'builder', label: 'Builder' },
    62|    { id: 'jv', label: 'JV Deals' }
    63|  ];
    64|
    65|  function viewerId() {
    66|    try {
    67|      var id = localStorage.getItem('ivx_viewer_id');
    68|      if (!id) {
    69|        id = 'guest-' + Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
    70|        localStorage.setItem('ivx_viewer_id', id);
    71|      }
    72|      return id;
    73|    } catch (e) { return 'guest-anon'; }
    74|  }
    75|  var VIEWER = viewerId();
    76|
    77|  /* ---------- analytics beacon queue ---------- */
    78|  var eventQueue = [];
    79|  function track(ev) {
    80|    ev.viewer_id = VIEWER;
    81|    eventQueue.push(ev);
    82|    if (eventQueue.length >= 10) flushEvents(false);
    83|  }
    84|  function flushEvents(useBeacon) {
    85|    if (eventQueue.length === 0) return;
    86|    var payload = JSON.stringify({ events: eventQueue.splice(0, eventQueue.length) });
    87|    var url = API + '/api/ivx/video-platform/events';
    88|    if (useBeacon && navigator.sendBeacon) {
    89|      navigator.sendBeacon(url, new Blob([payload], { type: 'application/json' }));
    90|    } else {
    91|      fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: payload }).catch(function () {});
    92|    }
    93|  }
    94|  setInterval(function () { flushEvents(false); }, 5000);
    95|  document.addEventListener('visibilitychange', function () { if (document.hidden) flushEvents(true); });
    96|  window.addEventListener('pagehide', function () { flushEvents(true); });
    97|
    98|  /* ---------- HLS ---------- */
    99|  var hlsLoading = null;
   100|  function loadHlsJs() {
   101|    if (window.Hls) return Promise.resolve();
   102|    if (hlsLoading) return hlsLoading;
   103|    hlsLoading = new Promise(function (resolve) {
   104|      var s = document.createElement('script');
   105|      s.src = HLS_CDN; s.async = true;
   106|      s.onload = function () { resolve(); };
   107|      s.onerror = function () { resolve(); };
   108|      document.head.appendChild(s);
   109|    });
   110|    return hlsLoading;
   111|  }
   112|  function attachSource(video, hlsUrl, fallbackUrl) {
   113|    if (video.__ivxAttached) return;
   114|    video.__ivxAttached = true;
   115|    if (!hlsUrl) { if (fallbackUrl) video.src = fallbackUrl; return; }
   116|    if (video.canPlayType('application/vnd.apple.mpegurl')) { video.src = hlsUrl; return; }
   117|    loadHlsJs().then(function () {
   118|      if (window.Hls && window.Hls.isSupported()) {
   119|        var h = new window.Hls({ capLevelToPlayerSize: true, autoStartLoad: true, maxBufferLength: 15 });
   120|        h.on(window.Hls.Events.ERROR, function (_e, data) {
   121|          if (data && data.fatal) { try { h.destroy(); } catch (e) {} if (fallbackUrl) video.src = fallbackUrl; }
   122|        });
   123|        h.loadSource(hlsUrl);
   124|        h.attachMedia(video);
   125|        video.__ivxHls = h;
   126|      } else if (fallbackUrl) {
   127|        video.src = fallbackUrl;
   128|      }
   129|    });
   130|  }
   131|
